from src.nodes.base import BaseNode
from src.utils.prism_core import resolve_prism_core

class PrismCreateCategoryNode(BaseNode):
    name = "Prism: Create Category"
    category = "DCCs"

    def __init__(self):
        super().__init__()
        self.icon_path = "icons/prism_icon.png"
        self.add_input("core", "any")
        self.add_input("entity", "dict")
        self.add_input("department", "string", widget_type="text", default="fx")
        self.add_input("task", "string", widget_type="text", default="fire")
        self.add_output("success", "bool")

    async def execute(self, inputs):
        core = resolve_prism_core(inputs)
        entity = inputs.get('entity') or {}
        dept = inputs.get('department') or ''
        task = inputs.get('task') or ''
        if core is None:
            self.log_error("No PrismCore found. Add a prism_core_init node to your graph and connect its exec_out before this node.")
            return {'success': False}
        try:
            core.entities.createCategory(entity, dept, task)
            self.log_success(f"Created category {dept}/{task} on {entity}.")
            await self.set_output('exec_out', True)
            return {'success': True}
        except Exception as e:
            self.log_error(f"createCategory failed: {e}")
            return {'success': False}

def register_node():
    return PrismCreateCategoryNode
